<?php require_once __DIR__ . '/../config/database.php'; require_once __DIR__ . '/../includes/auth.php'; require_login();
$rows=$pdo->query('SELECT id,full_name,company_name,source,service_interest,stage,priority FROM leads WHERE deleted_at IS NULL ORDER BY created_at DESC LIMIT 500')->fetchAll();
?><!doctype html><html><head><meta charset="utf-8"><title>Lead Summary</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet"></head><body class="p-4"><h3>Lead Summary</h3><table class="table table-sm table-bordered"><thead><tr><th>ID</th><th>Name</th><th>Company</th><th>Source</th><th>Service</th><th>Stage</th><th>Priority</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?= (int)$r['id'] ?></td><td><?= htmlspecialchars($r['full_name']) ?></td><td><?= htmlspecialchars($r['company_name']) ?></td><td><?= htmlspecialchars($r['source']) ?></td><td><?= htmlspecialchars($r['service_interest']) ?></td><td><?= htmlspecialchars($r['stage']) ?></td><td><?= htmlspecialchars($r['priority']) ?></td></tr><?php endforeach;?></tbody></table><script>window.print()</script></body></html>
